var ADMIN_USER_NOTICE_DURATION=3e3,ADMIN_USER_REDIRECT_DELAY=1500,AdminUser={deactivate:function(e,t,n){confirm("确定永久停用“"+t+"”？账号资料将被清除。")&&confirm("再次确认：停用后无法恢复，原手机号可重新注册。")&&$.ajax({url:Label.servePath+"/admin/user/"+e+"/deactivate",type:"POST",headers:{csrfToken:n},success:function(e){0===e.code?(Util.notice("success",ADMIN_USER_REDIRECT_DELAY,e.msg),setTimeout(function(){window.location.href=Label.servePath+"/admin/users"},ADMIN_USER_REDIRECT_DELAY)):Util.notice("warning",ADMIN_USER_NOTICE_DURATION,e.msg)},error:function(e){Util.notice("warning",ADMIN_USER_NOTICE_DURATION,e.status+" "+e.statusText)}})}};